#!/usr/bin/env python3
"""
bootstrap_glycan_pulldown_v2.py -- Complete glycan pulldown design pipeline.

Supersedes: bootstrap_click_site_predictor.py, bootstrap_bead_linker_design.py,
            bootstrap_pulldown_selector.py

Deploys 8 files. Includes EPS_WATER_BRIDGE for G5 compatibility.

Depends on: bootstrap_suprabank_ingest.py + bootstrap_suprabank_refit.py
Apply BEFORE bootstrap_glycan_g2g5.py (g2g5 will supersede scorer.py and contact_maps.py).
"""

import base64, os, sys

FILES = {
    'glycan/parameters_v23.py': '',
    'glycan/contact_maps.py': '',
    'glycan/click_site_predictor.py': '',
    'glycan/bead_linker_design.py': '',
    'glycan/pulldown_selector.py': '',
    'glycan/tests/test_click_site.py': '',
    'glycan/tests/test_bead_linker.py': '',
    'glycan/tests/test_pulldown_selector.py': '',
}


def find_root():
    d = os.path.abspath(os.getcwd())
    for _ in range(5):
        if os.path.isfile(os.path.join(d, "core", "universal_schema.py")):
            return d
        parent = os.path.dirname(d)
        if parent == d:
            break
        d = parent
    d = os.path.abspath(os.path.join(os.getcwd(), ".."))
    if os.path.isfile(os.path.join(d, "core", "universal_schema.py")):
        return d
    print("ERROR: Cannot find MABE repo root.")
    sys.exit(1)


def main():
    root = find_root()
    print(f"MABE root: {root}")
    print()
    for relpath, b64data in FILES.items():
        fullpath = os.path.join(root, relpath)
        os.makedirs(os.path.dirname(fullpath), exist_ok=True)
        content = base64.b64decode(b64data).decode("utf-8")
        with open(fullpath, "w", encoding="utf-8") as f:
            f.write(content)
        print(f"  written: {relpath}")
    print()
    print(f"Bootstrap complete: {len(FILES)} files written.")
    print("Apply bootstrap_glycan_g2g5.py AFTER this bootstrap.")
    print("Test: python -m pytest glycan/tests/test_click_site.py glycan/tests/test_bead_linker.py glycan/tests/test_pulldown_selector.py -v")


if __name__ == "__main__":
    main()